#!/usr/bin/env python3
"""Add 15 Macbeth character portraits (ids a135-a149) to assets/assets.json.
Run once from your repo root:  python3 apply_portraits_macbeth.py"""
import json, os, sys, hashlib
HERE=os.path.dirname(os.path.abspath(__file__)); ASSETS=os.path.join(HERE,"assets","assets.json"); MANIFEST=os.path.join(HERE,"manifest.json")
LABELS={"a135": "macbeth", "a136": "lady_macbeth", "a137": "banquo", "a138": "duncan", "a139": "witches", "a140": "malcolm", "a141": "macduff", "a142": "ross", "a143": "hecate", "a144": "fleance", "a145": "donalbain", "a146": "murderers", "a147": "apparitions", "a148": "siward", "a149": "porter"}
NEW={
  "a135": "",
  "a136": "",
  "a137": "",
  "a138": "",
  "a139": "",
  "a140": "",
  "a141": "",
  "a142": "",
  "a143": "",
  "a144": "",
  "a145": "",
  "a146": "",
  "a147": "",
  "a148": "",
  "a149": "",
}
def main():
    if not os.path.exists(ASSETS): sys.exit(f"[art] ERROR: {ASSETS} not found. Run from repo root.")
    A=json.load(open(ASSETS)); bak=ASSETS+".bak"
    if not os.path.exists(bak): json.dump(A,open(bak,"w"),separators=(",",":")); print(f"[art] backup: {bak}")
    for a,b in NEW.items():
        t="added" if a not in A else ("unchanged" if A[a]==b else "replaced"); A[a]=b
        print(f"[art] {a}  {LABELS.get(a,a):14s} {t}")
    json.dump(A,open(ASSETS,"w"),separators=(",",":")); print(f"[art] wrote {ASSETS}")
    if os.path.exists(MANIFEST):
        try:
            m=json.load(open(MANIFEST)); have={r.get("id") for r in m.get("assets",[])}
            for a,b in NEW.items():
                rec={"id":a,"media_type":"image/jpeg","bytes_b64":len(b),"sha256":hashlib.sha256(b.encode()).hexdigest(),"occurrences":1}
                if a in have:
                    for r in m["assets"]:
                        if r.get("id")==a: r.update(rec)
                else: m.setdefault("assets",[]).append(rec)
            json.dump(m,open(MANIFEST,"w"),indent=1); print("[art] manifest refreshed")
        except Exception as e: print(f"[art] (manifest skip: {e})")
    print("\n[art] Done. Next: swap in the new game.src.html, then python3 build.py")
if __name__=="__main__": main()
